# ── HELPERS ──────────────────────────────────────────────────────────────────

def run_ddl(sql: str, desc: str):
    resp = requests.post(
        RPC_URL,
        headers=HEADERS,
        json={"query": sql.strip().rstrip(";")},
        timeout=60,
    )
    if resp.status_code not in (200, 201):
        print(f"  ✗ FAILED ({resp.status_code}): {desc}")
        print(f"    {resp.text[:300]}")
        sys.exit(1)
    print(f"  ✓ {desc}")
    return resp.json()


def rest_clear(table: str):
    resp = requests.delete(
        f"{SUPABASE_URL}/rest/v1/{table}",
        headers={**HEADERS, "Prefer": "return=minimal"},
        params={"id": "gte.0"},
        timeout=60,
    )
    if resp.status_code not in (200, 204, 404):
        print(f"  ✗ FAILED clearing {table} ({resp.status_code}): {resp.text[:200]}")
        sys.exit(1)


def rest_insert(table: str, batch: list):
    payload = [{"staff_name": r[0], "staff_id": r[1], "date": r[2], "shift": r[3]}
               for r in batch]
    resp = requests.post(
        f"{SUPABASE_URL}/rest/v1/{table}",
        headers={**HEADERS, "Prefer": "return=minimal"},
        json=payload,
        timeout=60,
    )
    if resp.status_code not in (200, 201):
        print(f"  ✗ FAILED insert into {table} ({resp.status_code}): {resp.text[:300]}")
        sys.exit(1)


def rest_count(table: str) -> int:
    resp = requests.head(
        f"{SUPABASE_URL}/rest/v1/{table}",
        headers={**HEADERS, "Prefer": "count=exact"},
        params={"select": "*"},
        timeout=30,
    )
    try:
        return int(resp.headers.get("content-range", "/0").split("/")[1])
    except Exception:
        return -1


def create_table(table: str):
    run_ddl(f"""
        CREATE TABLE IF NOT EXISTS {table} (
            id         BIGSERIAL PRIMARY KEY,
            staff_name TEXT NOT NULL,
            staff_id   TEXT,
            date       TEXT NOT NULL,
            shift      TEXT NOT NULL
        )
    """, f"CREATE TABLE {table}")
    run_ddl(f"CREATE INDEX IF NOT EXISTS idx_{table}_date  ON {table}(date)",
            f"  index date on {table}")
    run_ddl(f"CREATE INDEX IF NOT EXISTS idx_{table}_staff ON {table}(staff_name)",
            f"  index staff on {table}")
    run_ddl(f"CREATE INDEX IF NOT EXISTS idx_{table}_shift ON {table}(shift)",
            f"  index shift on {table}")


def main():
    month_list = sorted(MONTHLY_DATA.keys())
    total_records = sum(len(v) for v in MONTHLY_DATA.values())

    print("=" * 60)
    print("  CAMO Roster — Monthly Tables Migration")
    print(f"  Target  : {SUPABASE_URL}")
    print(f"  Months  : {len(month_list)}  ({month_list[0]} -> {month_list[-1]})")
    print(f"  Records : {total_records:,}")
    print("=" * 60)

    for i, table in enumerate(month_list, 1):
        recs = MONTHLY_DATA[table]
        print(f"\n[{i}/{len(month_list)}] {table}  ({len(recs)} records)")

        create_table(table)
        rest_clear(table)

        total_b = (len(recs) + BATCH_SIZE - 1) // BATCH_SIZE
        for b in range(total_b):
            chunk = recs[b * BATCH_SIZE:(b + 1) * BATCH_SIZE]
            rest_insert(table, chunk)

        count = rest_count(table)
        print(f"  -> {count} rows confirmed in {table}")

    print(f"\n{'='*60}")
    print(f"  All {len(month_list)} monthly tables created and populated!")
    print(f"{'='*60}")


if __name__ == "__main__":
    main()